INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"09895c7","title":"Капитан Марвел. Том 3. На своих крыльях","author":"Келли Сью ДеКонник","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1007069839/140/06f7/Kelli_Syu_DeKonnik__Kapitan_Marvel._Tom_3._Na_svoih_krylyah.jpg","isbn":"978-5-6043397-0-1","publisher":"Jellyfish Jam","pubDate":"2020","language":"","series":"Капитан Марвел","genres":["Комиксы","манга","графические романы"],"annotation":"Капитан Марвел отправилась в космос - но пора вернуться обратно!    За недолгую карьеру межзвёздного Мстителя Капитан Марвел неоднократно встречалась с худшими представителями галактики. Но теперь консорциум хаффенсаев наконец-то настиг Кэрол и Тик! Кэрол едва удалось уцелеть после предыдущей стычки с хаффенсаями…  Окажется ли удача на её стороне и в этот раз? Сможет ли Капитан Марвел совладать с кровожадными космическими пиратами? Делайте ставки!  А также: Кэрол оказалась втянута в заварушку с Чёрным Вихрем, таинственным зеркалом, которое искушает обещаниями невероятных сил.  А когда страсти улягутся, Кэрол вернётся на Землю спустя целый год межгалактических приключений. Но что её ждёт на родной планете?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-02","rating":3,"review":"","added":9999815,"hdCover":""},{"id":"09895c6","title":"Капитан Марвел. Том 2. На Стиле","author":"Келли Сью ДеКонник,Marcia Takara","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002999311/140/fcf5/__Kapitan_Marvel._Tom_2._Na_Stile.jpg","isbn":"978-5-6041718-6-8","publisher":"Jellyfish Jam","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Не успела Кэрол Дэнверс вернуться на свой корабль «Гаррисон», как тут же попала в новую передрягу: Реактивный Енот из Стражей Галактики раструбил всем, что кошка Чуи — на самом деле никакая не кошка, а представительница редкого инопланетного вида под названием флёркен. Теперь Кэрол и Ракете придётся отложить в сторону все разногласия и спасти не только Чуи, но и её потомство!Тем временем на корабль Капитана Марвел попадает Лайла Чени — рок-звезда и по совместительству мутант со способностью к телепортации. А также Кэрол получает письма с Земли от своих друзей и близких, из которых узнаёт о том, как один враг из её прошлого попытался отомстить!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-02","rating":3.5,"review":"","added":9999814,"hdCover":""},{"id":"09895c5","title":"Капитан Марвел. Том 1. Выше, дальше, быстрее, больше","author":"Давид Лопес,Келли Сью ДеКонник","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002777217/140/97cc/__Kapitan_Marvel._Tom_1._Vyshe_dalshe_bystree_bolshe.jpg","isbn":"978-5-6040823-1-7","publisher":"Jellyfish Jam","pubDate":"2018","language":"Русский","series":"Капитан Марвел","genres":["Комиксы","манга","графические романы"],"annotation":"С недавних пор Кэрол Дэнверс осела на Земле, но когда на нашу планету падает спасательная капсула с загадочной инопланетной девочкой, Капитан Марвел принимает судьбоносное решение - вернуться в космос! Ей предстоит схватка с силами Галактического Альянса и шпионами коварных спартанцев. К счастью, она будет не одна, ведь на помощь к ней придут не только новые друзья, но и старые знакомые из Стражей Галактики!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-02","rating":4,"review":"","added":9999813,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"09895c4","title":"Дэдпул против Отряда Икс","author":"Дуэйн Сверчински","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003019228/140/7710/Duejn_Sverchinski__Dedpul_protiv_Otryada_Iks.jpg","isbn":"978-5-04-102816-9","publisher":"Эксмо","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Как познакомились Дэдпул и Кейбл! Путешествие назад в суровые гипердетализированные 90-е, во времена, когда появились персонажи, которые изменят облик комиксов: Кейбл и Дэдпул! В этой истории мы узнаем подробности их знакомства: когда Кейбл вместе со своим новоявленным отрядом Икс ныряет в поток времени с целью остановить безрассудного наёмника Дэдпула до того, как он навсегда уничтожит историю Америки! Путешествуя от Боксёрского восстания и до наших дней, сможет ли отряд Кейбла спасти ход историиот вмешательства Дэдпула? Он еще не ДЕД и полон сил, но и команда не просила его устраивать исторический мИКС! (заметили, что мы придумали? Дед... Икс... неважно). Отряд Икс сильнее, но Дэдпул популярнее. Кто станет победителем?! Всё, что вы знали о совместных приключениях Кейбла и Дэдпула, - неправда, но не расстраивайтесь, вас ждёт история покруче! В книгу вошли комиксы \"Дэдпул против отряда Икс #1-4 от Дуэйна Сверчински и Пепе Ларраза.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-02","rating":4,"review":"","added":9999812,"hdCover":""},{"id":"09895c3","title":"Женщина-Халк. Том 2. Противозаконное поведение","author":"Чарльз Соул","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002031494/140/4cc4/Charlz_Soul__ZhenschinaHalk._Tom_2._Protivozakonnoe_povedenie.jpg","isbn":"978-5-91339-425-5","publisher":"Комильфо","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Женщина-Халк, Адская Кошка и Великан объединяются, чтобы спасти соседа по офису Джен — но что скрывает Хэнк Пим? Тем временем у Женщины-Халк появляется новый клиент — Капитан Америка! Кто-то из прошлого Кэпа вернулся, чтобы доставить всем неприятностей, и Женщина-Халк — последняя надежда Капитана, ведь адвокат обвинения — Мэтт Мёрдок! В этом деле века Женщина-Халк и Сорвиголова сражаются в суде и на улицах — но виновен ли в итоге Капитан Америка? И, в конце концов: тайна Синей Папки раскрыта! Адская Кошка расследует таинственное дело с изменением сознания, Женщина-Халк сражается с Титанией, а для Энджи Хуанг всё вполне может закончиться печально! Тайное становится явным, а Синяя Папка широко распахнута!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-02","rating":4,"review":"","added":9999811,"hdCover":""},{"id":"09895c2","title":"Женщина-Халк. Том 1. Закон и Беспорядок","author":"Хавьер Пулидо,Чарльз Соул,Рональд Уимберли","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001555504/140/e646/__ZhenschinaHalk._Tom_1._Zakon_i_Besporyadok.jpg","isbn":"978-5-91339-382-1","publisher":"Комильфо","pubDate":"2016","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Все знают, что у зелёной богини немалый опыт в спасении мира в составе мстителей и Фонда Будущего. Но Дженнифер Уолтерс сильна не только физически — она может задавить вас и кучей учёных степеней! Джен открыла собственную адвокатскую контору, но совмещать разбор дел и избиение плохих парней оказалось куда сложнее, чем она думала. Чего только стоит её первый клиент: когда Кристофф Вернард, сын Виктора фон Дума, добивается собственной экстрадиции, всё превращается в международный побег из тюрьмы в стиле Женщины-Халк! Далее: Женщина-Халк и Адская Кошка должны разгадать тайну Синей Папки — заговора, затрагивающего всю вселенную Marvel! Когда погибает важный для Женщины-Халк человек, она готова сразиться со всем миром — но кому верить? Женщина-Халк берёт на себя самую ужасную роль: роль ответчика!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-02","rating":3.5,"review":"","added":9999810,"hdCover":""},{"id":"09895c1","title":"Attack on Titan: Volume 16","author":"Hajime Isayama","type":"Манга","cover":"https://s1.livelib.ru/boocover/1001268760/140/4ec8/Hajime_Isayama__Attack_on_Titan_Volume_16.jpg","isbn":"978-1-61262-980-3","publisher":"Kodansha Comics","pubDate":"2015","language":"Английский","series":"Attack on Titan","genres":["Манга"],"annotation":"Captured by Rod Reiss, the rightful king, Krista and Eren finally have their memories back. What exactly happened to Eren, and what was the crime his father committed? Meanwhile, the Survey Corps desperately hunts for Eren, while at the same time seeking to legitimize their military coup. As the situation inside the walls comes to a head, the mysteries of the world of the Titans seem on the cusp of being solved at last!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-02","rating":5,"review":"","added":9999809,"hdCover":""},{"id":"09895c0","title":"Attack on Titan: Volume 15","author":"Hajime Isayama","type":"Манга","cover":"https://s1.livelib.ru/boocover/1001268758/140/2643/Hajime_Isayama__Attack_on_Titan_Volume_15.jpg","isbn":"978-1-61262-979-7","publisher":"Kodansha Comics","pubDate":"2015","language":"Английский","series":"Attack on Titan","genres":["Манга"],"annotation":"Hange''s interrogation of a Military Police squad has revealed that Krista (a.k.a. Historia Reiss) is the true heir to the throne. The Corps quickly moves to enthrone her as queen, but a homicidal MP leads a squad that abducts Eren and Krista and throws the Corps into disarray. With Erwin arrested and the Survey Corps on the edge of dissolution, are Levi and Hange finally out of options?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-02","rating":5,"review":"","added":9999808,"hdCover":""},{"id":"09895bf","title":"She-Hulk Vol. 2: Superhuman Law","author":"Juan Bobillo,Дэн Слотт","type":"Книга","cover":"https://s1.livelib.ru/boocover/1004130658/140/298b/__SheHulk_Vol._2_Superhuman_Law.jpg","isbn":"978-0785115700","publisher":"Marvel","pubDate":"2006","language":"Английский","series":"","genres":[],"annotation":"As a superhuman lawyer, She-Hulk has tried some of the strangest cases on Earth... but all of that is about to change! Empowered by the Living Tribunal, Shulkie is heading into deep space to practice Universal Law! Guest-starring Adam Warlock, Gamora, and Pip the Troll! Plus: Out of all of She-Hulk''s enemies, no one hates her more than Titania!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-02","rating":3.5,"review":"","added":9999807,"hdCover":""},{"id":"09895be","title":"Женщина-Халк. Одинокая зеленая женщина","author":"Juan Bobillo,Пол Пеллетьер,Ади Гранов,Дэн Слотт,Roland Paris,Marcelo Sosa,Tom Simmons,Don Hillsman,Chris Chuckry,показать всех","type":"Книга","cover":"https://s1.livelib.ru/boocover/1002741643/140/878f/__ZhenschinaHalk._Odinokaya_zelenaya_zhenschina.jpg","isbn":"2304-9057","publisher":"Ашет Коллекция, Панини Рус","pubDate":"2017","language":"Русский","series":"","genres":[],"annotation":"Жизнь одинокой девушки в Нью-Йорке не назовешь легкой. А если вы знаменитый юрист Дженнифер Уолтерс, известная также как Женщина-Халк, то безумные приключения вам просто гарантированы. Но теперь всеми любимую нефритовую великаншу ждет новое испытание – она начинает работать в компании, занимающейся правами сверхлюдей.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-02","rating":3,"review":"","added":9999806,"hdCover":""},{"id":"09895bd","title":"Attack on Titan: Volume 14","author":"Hajime Isayama","type":"Манга","cover":"https://s1.livelib.ru/boocover/1000971825/140/4116/Hajime_Isayama__Attack_on_Titan_Volume_14.jpg","isbn":"978-1-61262-680-2","publisher":"Kodansha Comics","pubDate":"2014","language":"Английский","series":"Attack on Titan","genres":["Манга"],"annotation":"Commander Erwin has finally come to a decision: Putting their own wealth and position ahead of the survival of humanity, the royal government is no longer fit to lead. To execute their leader''s most audacious plan yet, Eren and Krista will have to put themselves in peril yet again, and Armin, Mikasa, and the rest of the Survey Corps will have to turn from humanity''s guardians into traitors. If they fail this time, they''ll face not a Titan''s gaping mouth, but the gallows...","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-02","rating":5,"review":"","added":9999805,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
