SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"09895bc","title":"Attack on Titan: Volume 13","author":"Hajime Isayama","type":"Манга","cover":"https://s1.livelib.ru/boocover/1001182530/140/e9aa/Hajime_Isayama__Attack_on_Titan_Volume_13.jpg","isbn":"978-1-61262-679-6","publisher":"Kodansha Comics","pubDate":"2014","language":"Английский","series":"Attack on Titan","genres":["Манга"],"annotation":"At great cost to the Garrison and the Survey Corps, Commander Erwin has managed to recover Eren from the Titans who tried to carry him off. But during the battle, Eren manifested yet another power he doesn''t understand.  As Eren and Krista find new enemies, the Survey Corps faces threats from both inside and outside the walls. And what will happen to Ymir, now that she has decided to make herself the Titans'' prize?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-02","rating":5,"review":"","added":9999804,"hdCover":""},{"id":"09895bb","title":"The Sensational She-Hulk Volume 1","author":"Джон Бирн","type":"Книга","cover":"https://s1.livelib.ru/boocover/1007047618/140/d6df/Dzhon_Birn__The_Sensational_SheHulk_Volume_1.jpg","isbn":"9780785153061","publisher":"Marvel","pubDate":"2011","language":"","series":"The Sensational She-Hulk (1989)","genres":[],"annotation":"From Savage to Sensational! With John Byrne writing and penciling, witness She-Hulk go where no super hero has gone before: right through the 4th wall! See She-Hulk vs. Spider-Man! Beheaded! Against the wrath of Dr. Bong! Alongside Santa Claus! On her own Star Truck! Hosting her own golden age guest star! Guest-starring the Wasp, Mr. Fantastic and Razorback!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-02","rating":4.5,"review":"","added":9999803,"hdCover":""},{"id":"09895ba","title":"Некрополис","author":"Григорий Старостин","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002977164/140/6e0e/Grigorij_Starostin__Nekropolis.jpg","isbn":"978-5-9500800-0-5","publisher":"Vicious Membrane","pubDate":"2017","language":"","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-02","rating":4,"review":"","added":9999802,"hdCover":""},{"id":"09895b9","title":"Attack on Titan: Volume 12","author":"Hajime Isayama","type":"Манга","cover":"https://s1.livelib.ru/boocover/1000765370/140/c69f/Hajime_Isayama__Attack_on_Titan_Volume_12.jpg","isbn":"978-1-61262-678-9","publisher":"Kodansha Comics","pubDate":"2014","language":"Английский","series":"Attack on Titan","genres":["Манга"],"annotation":"Erwin and the Survey Corps desperately mount a rescue operation to take Eren back from the Colossus Titan and Armored Titan. But without the numbers to form up properly outside the walls, how can the humans catch up before they''re all slaughtered? Just whose side is Ymir on? And will Eren ever see his friends again?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-02","rating":5,"review":"","added":9999801,"hdCover":""},{"id":"09895b8","title":"Пираты Летучего Голландца","author":"Пьер Мак-Орлан,Давид Б.","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002186480/140/5e96/__Piraty_Letuchego_Gollandtsa.jpg","isbn":"978-5-99093-609-6","publisher":"КомФедерация","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Пираты-призраки «Летающего Голландца» устали от многолетних скитаний и грезят о вечном покое. От безысходности неприкаянные мертвецы нападают на другие судна, не оставляя в живых ни души. Но однажды они подбирают в море младенца, чудом выжившего после кораблекрушения... Какая участь ждёт малыша на корабле мёртвых пиратов? Как изменится их жизнь с появлением нежданного гостя? Прочтите ответ в этой потрясающе красивой комикс-адаптации рассказа Пьера Марк-Орлана, выполненной кистью гения французского комикса, автора великолепной \"Священной болезни\", Давида Б.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-02","rating":4.5,"review":"","added":9999800,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"09895b7","title":"ПиКачок. Истории из жизни. 001. Козырь","author":"Рудольфо","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003394486/140/2f69/Rudolfo__PiKachok._Istorii_iz_zhizni._001._Kozyr.jpg","isbn":"978-5-04-104094-9","publisher":"Комильфо, КомФедерация","pubDate":"2019","language":"","series":"ПиКачок","genres":["Комиксы","манга","графические романы"],"annotation":"ПИКАЧОК – это гипертрофированное создание с головой покемона и торсом Шварценеггера. Во время очередного сверхсекретного задания этот храбрый воин оказывается в самом логове зловещих зартранианцев: расы мутантов, захватывающих целые планеты с помощью популярной карточной игры. Воспользовавшись выносливостью Пикачка, они рассчитывают переместиться в другое измерение. И чем ближе герой узнаёт этих ехидных существ, тем сильнее уверяется, что их история не столь однозначна, как рассказывало ему его руководство…  «КомФедерация» вновь преподносит читателям комикс в стиле «трэш и угар», ещё сильнее расширяя географию изданных на русском авторов со всего мира, ведь безумный автор «Пикачка» Рудольфо родом из солнечной Португалии. И если после прочтения у вас возникает классический вопрос «Что курил автор?» – значит, мы всё делаем правильно, а автор не только курил.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-02","rating":4,"review":"","added":9999799,"hdCover":""},{"id":"09895b6","title":"Бетти и Вероника","author":"Адам Хьюз","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1005441679/140/e230/Adam_Hyuz__Betti_i_Veronika.jpg","isbn":"978-5-04-111661-3","publisher":"Комильфо","pubDate":"2020","language":"Русский","series":"Комильфо. Арчи (обложка)","genres":["Комиксы","манга","графические романы"],"annotation":"У нас в программе Бетти против Вероники! Любимицы Америки… ополчились друг на друга! Большая кофейная компания грозится захватить закусочную Попса. У Бетти и Вероники разные взгляды на эту проблему, и потому девушки сходятся в рукопашке! К чему приведёт эта непредсказуемая ситуация? Дружба трещит по швам, ногти ломаются, а города сгорают в пламени войны, которую развязали закадычные подруги! Улицы Ривердейла залиты алым и сверкают под напалмом страстей. Жизнь уже не будет прежней!  В этот многообещающий сборник вошли выпуски комикса \"Бетти и Вероника\" #1-3 от легендарного автора комиксов Адама Хьюза!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-02","rating":3.5,"review":"","added":9999798,"hdCover":""},{"id":"09895b5","title":"Могучие Рейнджеры Морферы Силы. Год первый. Полное издание.","author":"Кайл Хиггинс","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1006455415/140/ef5f/Kajl_Higgins__Moguchie_Rejndzhery_Morfery_Sily._God_pervyj._Polnoe_izdanie..jpg","isbn":"978-5-04-119117-7","publisher":"Комильфо","pubDate":"2021","language":"Русский","series":"Комильфо. Комиксы по фильмам, играм и сериалам","genres":["Комиксы","манга","графические романы"],"annotation":"ВПЕРЁД, МОГУЧИЕ РЕЙНДЖЕРЫ! Добро пожаловать в Энджел Гроув, родной город Могучих Рейнджеров, в котором еженедельные нападения монстров стали рутиной! Томми Оливер даже не успел освоиться в новой школе, когда злодейка Рита Репульса сделала его Зелёным Рейнджером. Но теперь, освободившись от её злых чар, он пытается найти баланс между тягостью школьной жизни, общением с новыми друзьями и той опасностью, которая приходит с жизнью в роли героя.  Давние фанаты хитового шоу «Могучие Рейнджеры» и те, кто только знакомится с этой вселенной, откроют для себя увлекательный мир, наполненный захватывающим духом приключений и сердечной добротой их героев. Комикс не повторяет сюжет сериала, раскрывая историю Рейнджеров с совершенно новой стороны. Вместе с тем автор серии Кайл Хиггинс сохранил все культовые элементы, за которые эту франшизу так любят её поклонники. Динозорды, Зордон, Альфа 5 и многие другие знаковые персонажи - все в сборе.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-02","rating":4,"review":"","added":9999797,"hdCover":""},{"id":"09895b4","title":"Современный Человек-Паук. Катаклизм","author":"Брайан Майкл Бендис","type":"Книга","cover":"https://s1.livelib.ru/boocover/1007040379/140/3878/Brajan_Majkl_Bendis__Sovremennyj_ChelovekPauk._Kataklizm.jpg","isbn":"","publisher":"Зодиак","pubDate":"2021","language":"","series":"Современный Человек-Паук. Майлз Моралес","genres":[],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-01","rating":4.5,"review":"","added":9999796,"hdCover":""},{"id":"09895b3","title":"Шедевральные комиксы","author":"Роберт Сикоряк","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002726388/140/0e25/Robert_Sikoryak__Shedevralnye_komiksy.jpg","isbn":"978-5-99093-658-3","publisher":"КомФедерация","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"«Шедевральные комиксы» Роберта Сикоряка — гениальная книга, которая объединила классические литературные произведения с героями популярных комиксов. Мефистофель в теле кота Гарфилда, Малыш Немо из Сонной страны на страницах «Портрета Дориана Грея», главные герои «В ожидании Годо» — Бивис и Баттхед, а вместо баек из склепа хранитель расскажет читателям про «Грозовой перевал» Бронте. Ах да, та самая картинка Бэтмена-Раскольникова, которую вы не раз встречали в интернете, тоже из этой книги!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-01","rating":3.5,"review":"","added":9999795,"hdCover":""},{"id":"09895b2","title":"Безнадёжный. Книга 1","author":"Марк Уэйд,Питер Краузе","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002824612/140/4b63/__Beznadjozhnyj._Kniga_1.jpg","isbn":"978-5-04-094514-6","publisher":"Fanzon","pubDate":"2018","language":"Русский","series":"Комиксы. Новая Вселенная Супергероев","genres":["Комиксы","манга","графические романы"],"annotation":"Что, если величайший в мире герой станет величайшим злодеем?  Безграничная сила, непробиваемая кожа, неизмеримая скорость, антигравитация. Кто он - спаситель мира или самый страшный убийца в истории? Только бывшие товарищи по команде смогут остановить его неистовство... Если успеют раскрыть секреты этого могущественного и свирепого существа. Что делает героя БЕЗНАДЁЖНЫМ?  Захватывающая история о несущем разрушение супергерое от лауреатов премии Айснера!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-01","rating":4.5,"review":"","added":9999794,"hdCover":""},{"id":"09895b1","title":"Валериан. Книга 1","author":"Пьер Кристен,Жан-Клод Мезьер","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002340096/140/c854/__Valerian._Kniga_1.jpg","isbn":"978-5-389-12719-7","publisher":"Азбука, Азбука-Аттикус","pubDate":"2017","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Валериан и Лорелин, придуманные талантливыми Пьером Кристеном и Жан-Клодом Мезьером, впервые появились на страницах журнала «Pilote» в 1967 году. Эти оригинальные истории сразу же стали звездами первой величины на небосклоне научной фантастики.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-01","rating":4.5,"review":"","added":9999793,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"09895b0","title":"Attack on Titan: Volume 11","author":"Hajime Isayama","type":"Манга","cover":"https://s1.livelib.ru/boocover/1000744955/140/7f23/Hajime_Isayama__Attack_on_Titan_Volume_11.jpg","isbn":"978-1-61262-677-2","publisher":"Kodansha Comics","pubDate":"2014","language":"Английский","series":"Attack on Titan","genres":["Манга"],"annotation":"Thanks to Eren''s timely arrival, the 104th has managed to turn the tide at Wall Rose. But this momentary victory forces two more traitors into a corner – and the identity of the Titans who have been destroying the walls is revealed! What can Eren do against the two most dangerous monsters humanity has ever faced? And who else might be an enemy in disguise?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-01","rating":5,"review":"","added":9999792,"hdCover":""},{"id":"09895af","title":"Attack on Titan: Volume 10","author":"Hajime Isayama","type":"Манга","cover":"https://s1.livelib.ru/boocover/1000744954/140/81ee/Hajime_Isayama__Attack_on_Titan_Volume_10.jpg","isbn":"978-1-61262-676-5","publisher":"Kodansha Comics","pubDate":"2013","language":"Английский","series":"Attack on Titan","genres":["Манга"],"annotation":"With no combat gear and Wall Rose breached, the 104th scrambles to evacuate the villages in the Titans'' path. On their way to the safety of Wall Sheena, they decide to spend the night in Utgart Castle. But their sanctuary becomes a slaughterhouse when they discover that, for some reason, these Titans attack at night!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-01","rating":5,"review":"","added":9999791,"hdCover":""},{"id":"09895ae","title":"Attack on Titan: Volume 9","author":"Isayama Hajime","type":"Манга","cover":"https://s1.livelib.ru/boocover/1000744953/140/3ab1/Isayama_Hajime__Attack_on_Titan_Volume_9.jpg","isbn":"978-1-61262-548-5","publisher":"Kodansha Comics","pubDate":"2013","language":"Английский","series":"Attack on Titan","genres":["Манга"],"annotation":"Eren is still resting from his brutal fight with the female Titan, when word reaches the interior that the impossible has happened: Wall Rose itself has been breached, and Titans are pouring through the gap! The emergency casts new urgency over Armin and Hange''s questions about how the walls were built, and what humanity can do to restore them...","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-01","rating":5,"review":"","added":9999790,"hdCover":""},{"id":"09895ad","title":"Attack on Titan: No Regrets 2","author":"Хадзимэ Исаяма,Хикару Суруга,Ган Снарк","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000971861/140/7ede/__Attack_on_Titan_No_Regrets_2.jpg","isbn":"978-1-61262-943-8","publisher":"Kodansha Comics","pubDate":"2014","language":"Английский","series":"Attack on Titan","genres":["Манга","Комиксы","манга","графические романы"],"annotation":"Erwin''s political enemies have hired Levi and his crew to take back some incriminating documents. Their reward: the right to live a proud life above ground, in the royal capital. But deep in Titan territory, it''s going to be tough to break formation and steal from a squad leader, and Levi still insists on killing the man who humiliated him after the mission is complete. Of course, beyond the walls anything can happen, and a sudden change in Levi''s fortunes will force him to face the greatest regret in his life...  Prequel to Attack on Titan.  Story by Gun Snark and Art by Hikaru Suruga.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-01","rating":4.5,"review":"","added":9999789,"hdCover":""},{"id":"09895ac","title":"Attack on Titan: No Regrets 1","author":"Хадзимэ Исаяма,Хикару Суруга,Ган Снарк","type":"Манга","cover":"https://s1.livelib.ru/boocover/1001079992/140/3c39/__Attack_on_Titan_No_Regrets_1.jpg","isbn":"978-1-61262-941-4","publisher":"Kodansha Comics","pubDate":"2014","language":"Английский","series":"Attack on Titan","genres":["Манга","Боевое фэнтези"],"annotation":"The young Erwin Smith is a rising star in the Survey Corps, humanity''s only hope of defeating the man-eating monsters known as Titans. Ruthless and dispassionate, Erwin''s mind is devoted to strategies and intrigue. But beneath Erwin''s feet is another world, the Underground, where humans are born and die surrounded by the garbage the Capital throws away. Here, the criminal Levi survives on his wits and agility. But when these two ambitious men cross paths, who will prove himself stronger?  Prequel to Attack on Titan.  Story by Gun Snark and Art by Hikaru Suruga.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-01","rating":4.5,"review":"","added":9999788,"hdCover":""},{"id":"09895ab","title":"Attack on Titan: Volume 8","author":"Hajime Isayama","type":"Манга","cover":"https://s1.livelib.ru/boocover/1000744952/140/5b13/Hajime_Isayama__Attack_on_Titan_Volume_8.jpg","isbn":"978-1-61262-547-8","publisher":"Kodansha Comics","pubDate":"2013","language":"Английский","series":"Attack on Titan","genres":["Манга"],"annotation":"The expedition outside the wall was Eren''s chance to prove himself. But it failed, and the female Titan is free once more! With his squad dead, Eren faces a royal summons. Will Mikasa and Armin have to betray their king to save their friend? And can they discover the female Titan''s identity before she kills again?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-01","rating":5,"review":"","added":9999787,"hdCover":""},{"id":"09895aa","title":"Attack on Titan: Volume 7","author":"Hajime Isayama","type":"Манга","cover":"https://s1.livelib.ru/boocover/1000744947/140/038e/Hajime_Isayama__Attack_on_Titan_Volume_7.jpg","isbn":"978-1-61262-256-9","publisher":"Kodansha Comics","pubDate":"2013","language":"Английский","series":"Attack on Titan","genres":["Манга"],"annotation":"The Survey Corps sets a cunning trap to capture the mysterious Abnormal Titan that broke through their ranks. As Arwin tries to determine the grotesque creature''s identity and purpose, scouts report Titans closing in on all sides! But they don''t seem to be after the humans - instead they''re targeting the Titan!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-01","rating":5,"review":"","added":9999786,"hdCover":""},{"id":"09895a9","title":"Attack on Titan: Volume 6","author":"Hajime Isayama","type":"Манга","cover":"https://s1.livelib.ru/boocover/1000744946/140/a3c7/Hajime_Isayama__Attack_on_Titan_Volume_6.jpg","isbn":"978-1-61262-255-2","publisher":"Kodansha Comics","pubDate":"2013","language":"Английский","series":"Attack on Titan","genres":["Манга"],"annotation":"On the way to Eren''s home, deep in Titan territory, the Survey Corps ranks are broken by a charge led by a female Titan! But this Abnormal is different - she kills not to eat but to protect herself, and she seems to be looking for someone. Armin comes to a shocking conclusion: she''s a human in a Titan''s body, just like Eren!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-01","rating":5,"review":"","added":9999785,"hdCover":""},{"id":"09895a8","title":"Attack on Titan: Volume 5","author":"Hajime Isayama","type":"Манга","cover":"https://s1.livelib.ru/boocover/1000744945/140/6b1b/Hajime_Isayama__Attack_on_Titan_Volume_5.jpg","isbn":"978-1-61262-254-5","publisher":"Kodansha Comics","pubDate":"2013","language":"Английский","series":"Attack on Titan","genres":["Манга"],"annotation":"Thanks to Eren, humanity has taken the town of Trost back from the Titans. Exhausted, Eren falls into a coma for three days - and wakes in shackles, staring at Erwin Smith, leader of the Survey Corps. Certain that Eren''s father''s research holds the key to the mystery of the Titans'' rise, Smith wants an expedition to retrieve it from the house where Eren grew up. But that''s deep in Titan territory, and to get there Eren will need to master a power he still doesn''t fully understand...","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-01","rating":5,"review":"","added":9999784,"hdCover":""},{"id":"09895a7","title":"Семь Смертных Грехов. Книга 3","author":"Накаба Судзуки","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1004591926/140/2732/Nakaba_Sudzuki__Sem_Smertnyh_Grehov._Kniga_3.jpg","isbn":"978-5-91996-311-0","publisher":"XL Media","pubDate":"2020","language":"Русский","series":"Семь Смертных Грехов / Nanatsu no Taizai","genres":["Комиксы","манга","графические романы"],"annotation":"Постепенное воссоединение Семи Смертных Грехов продолжается: к Мелиодасу и великанше Диане примкнули бессмертный Бан и король фей Кинг. Но предстоит найти еще трех товарищей, а также реликвии — особое оружие, которое делает Смертные Грехи гораздо сильнее. Поиски реликвий приводят героев в город Вайзел, где проходит турнир, наградой в котором объявлен огромный молот — потерянное оружие Дианы. Делать нечего: надо участвовать в турнире, даже если при этом придется в очередной раз схлестнуться со Святыми рыцарями!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-01","rating":4.5,"review":"","added":9999783,"hdCover":""},{"id":"09895a6","title":"Attack on Titan: Volume 4","author":"Hajime Isayama","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000744943/140/2176/Hajime_Isayama__Attack_on_Titan_Volume_4.jpg","isbn":"978-1-61262-253-8","publisher":"Kodansha Comics","pubDate":"2013","language":"Английский","series":"Attack on Titan","genres":["Комиксы","манга","графические романы"],"annotation":"The Survey Corps develop a risky gambit: have Eren in Titan form attempt to repair Wall Rose, reclaiming human territory from the monsters for the first time in a century. But Titan-Eren''s self-control is far from perfect, and when he goes on a rampage, not even Armin can stop him! With the survival of humanity on his massive shoulders, will Eren be able to return to his senses, or will he lose himself forever?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-01","rating":5,"review":"","added":9999782,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"09895a5","title":"Семь Смертных Грехов. Книга 2","author":"Накаба Судзуки","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003631762/140/6949/Nakaba_Sudzuki__Sem_Smertnyh_Grehov._Kniga_2.jpg","isbn":"978-5-91996-280-9","publisher":"XL Media","pubDate":"2020","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Мелиодас, Диана и принцесса Элизабет нашли еще одного из Смертных Грехов — Бана, который также известен как Грех Лисьей Жадности. Но тот томится в заключении в неприступной тюрьме Баста, тому же герои по дороге попадают в ловушку Святых рыцарей. Смогут ли Мелиодас и Диана воссоединиться со старым товарищем и отыскать остальные Смертные Грехи? И главное — все ли будут рады воссоединению?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-01","rating":4.5,"review":"","added":9999781,"hdCover":""},{"id":"09895a4","title":"Семь Смертных Грехов. Книга 1","author":"Накаба Судзуки","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003162702/140/2ef4/Nakaba_Sudzuki__Sem_Smertnyh_Grehov._Kniga_1.jpg","isbn":"978-5-91996-263-2","publisher":"XL Media","pubDate":"2019","language":"Русский","series":"Семь Смертных Грехов / Nanatsu no Taizai","genres":["Комиксы","манга","графические романы"],"annotation":"Для королевства Лионесс настали черные дни: власть захватила элита королевских войск, Святые Рыцари, которые заточили в тюрьму королевскую семью и творят в стране произвол. Принцессе Элизабет удается сбежать, и она решает искать помощи у легендарных рыцарей-мятежников, которые известны в народе как Семь Смертных Грехов. По счастливой случайности девушка забредает в весьма странный кабак, хозяином которого оказывается как раз один из тех, кого она ищет: Смертный Грех Гнева, Мелиодас. Он соглашается помочь Элизабет и отправляется с ней на поиски бывших товарищей...","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-01","rating":4.5,"review":"","added":9999780,"hdCover":""},{"id":"09895a3","title":"Attack on Titan: Volume 3","author":"Hajime Isayama","type":"Манга","cover":"https://s1.livelib.ru/boocover/1000742826/140/7868/Hajime_Isayama__Attack_on_Titan_Volume_3.jpg","isbn":"978-1-61262-026-8","publisher":"Kodansha Comics","pubDate":"2012","language":"Английский","series":"Attack on Titan","genres":["Манга"],"annotation":"The last thing Eren remembers before blacking out, a Titan had bitten off his arm and leg and was getting ready to eat him alive. Much to his surprise he wakes up without a scratch on him, with a crowd of angry soldiers screaming for his blood. What strange new power has he awakened, and what will happen when the boy devoted to destroying the Titans becomes one himself?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-01","rating":5,"review":"","added":9999779,"hdCover":""},{"id":"09895a2","title":"Attack on Titan: Volume 2","author":"Hajime Isayama","type":"Манга","cover":"https://s1.livelib.ru/boocover/1000742452/140/3618/Hajime_Isayama__Attack_on_Titan_Volume_2.jpg","isbn":"978-1-61262-025-1","publisher":"Kodansha Comics","pubDate":"2012","language":"Английский","series":"Attack on Titan","genres":["Манга"],"annotation":"The Colossal Titan has breached humanity''s first line of defense, Wall Maria. Mikasa, the 104th Training Corps'' ace and Eren''s best friend, may be the only one capable of defeating them, but beneath her calm exterior lurks a dark past. When all looks lost, a new Titan appears and begins to slaughter its fellow Titans. Could this new monster be a blessing in disguise, or is the truth something much more sinister?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-01","rating":5,"review":"","added":9999778,"hdCover":""},{"id":"09895a1","title":"Attack on Titan: Volume 1","author":"Hajime Isayama","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000742229/140/c3f0/Hajime_Isayama__Attack_on_Titan_Volume_1.jpg","isbn":"978-1-61262-024-4","publisher":"Kodansha Comics","pubDate":"2012","language":"Английский","series":"Attack on Titan","genres":["Манга","Комиксы","манга","графические романы"],"annotation":"Humankind is down to just a few thousand people who live in a city surrounded by three concentric walls. The walls protect them from their enemies, the ravenous giants known as the Titans. The Titans appear to have only one purpose: to consume humanity.  For one hundred years, what''s left of mankind has lived in the city on earth, protected by walls that tower over even the Titans. Untouched by the Titans for a century, humanity has become complacent. But Eren Jaeger has had enough. While his fellow citizens are content to hide, Jaeger has the passion to take action to not only protect the city, but to learn what the Titans actually are. On his first mission he comes face to face with horrors beyond his imagination... and secrets from his own past that could shift the tides of war.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-01","rating":5,"review":"","added":9999777,"hdCover":""},{"id":"09895a0","title":"Жертвы чёрного дождя","author":"Кэйдзи Накадзава","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002446805/140/94cc/Kejdzi_Nakadzava__Zhertvy_chjornogo_dozhdya.jpg","isbn":"978-5-905295-39-3","publisher":"Alt Graph","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Сборник «Жертвы чёрного дождя» включает рассказы, которые Кэйдзи Накадзава нарисовал в конце 60-х годов, когда в японском обществе царило негласное табу на упоминание трагедий в Хиросиме и Нагасаки. Накадзава стал одним из первых авторов в Японии, кто отважился рассказать о жертвах атомной бомбардировки, которые даже спустя десятилетия не могли вернуться к нормальной жизни. Эти тяжелые и порой жестокие рассказы сейчас могут восприниматься неоднозначно, но они дают прекрасное представление о том, в каком эмоциональном состоянии находился Кэйдзи Накадзава в то время.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-01","rating":3.5,"review":"","added":9999776,"hdCover":""},{"id":"098959f","title":"Negan Lives!","author":"Роберт Киркман","type":"Книга","cover":"https://s1.livelib.ru/boocover/1006990666/140/05ec/Robert_Kirkman__Negan_Lives.jpg","isbn":"7-09853-03030-0-00111","publisher":"Image Comics","pubDate":"2020","language":"","series":"The Walking Dead","genres":[],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-01","rating":4,"review":"","added":9999775,"hdCover":""},{"id":"098959e","title":"Ходячие мертвецы. Том 32. Покойся с миром","author":"Роберт Киркман,Клифф Ратбёрн,Стефано Гаудиано,Чарли Адлард,Charlie Adlar,показать всех","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003621314/140/2b4d/__Hodyachie_mertvetsy._Tom_32._Pokojsya_s_mirom.jpg","isbn":"978-5-04-107462-3","publisher":"Комильфо","pubDate":"2019","language":"Русский","series":"Ходячие мертвецы","genres":["Комиксы","манга","графические романы"],"annotation":"Сколько часов в день вы не тратите, просиживая перед телевизором? Когда в последний раз кто-нибудь из нас НА САМОМ ДЕЛЕ старался, чтобы получить желаемое? Давно ли кому-то из нас действительно было НУЖНО то, чего мы постоянно ХОТИМ? Мир, который мы знали, исчез. На смену миру торговли и пустого потребительства пришел мир выживания и ответственности. Эпидемия апокалиптических масштабов прокатилась по планете, пробудив мертвых, которые начали пожирать живых. За несколько месяцев человеческое общество было разрушено. Исчезли правительства, магазины, доставка почты, кабельное телевидение. В мире, где правят мертвые, мы наконец вынуждены начать жить.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-12","rating":5,"review":"","added":9999774,"hdCover":""}]');
